queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasOpportunities ?child ; p:hasCareer_Pathways ?parent . } GROUP BY ?child }
  ?child p:Value ?value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Career_Pathways } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?value WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasOpportunities ?child ; p:hasCareer_Pathways ?parent . } GROUP BY ?child }
  ?child p:Value ?value .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Career_Pathways } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?value WHERE {
  ?career_pathways_opportunities a :Career_Pathways_Opportunities .
  ?opportunities a :Opportunities .
  ?career_pathways_opportunities p:hasOpportunities ?opportunities .
  ?career_pathways a :Career_Pathways .
  ?career_pathways_opportunities p:hasCareer_Pathways ?career_pathways .
  ?career_pathways p:name ?name .
  ?opportunities p:Value ?value .
} }
}
